//   port_notes:    0
//   unsafe_blocks: 0
//   notes:         drives new_state → open_libs → load_string → pcall_k.
//                  Designed to surface the first todo!() panic on a hello-
//                  world program, not to be a complete interpreter.
// ──────────────────────────────────────────────────────────────────────────
